import { Point } from '@visx/brush/lib/types';
import { useCallback } from 'react';

import { getTokenComputedStyle } from '../../../../../utils/getTokenComputedStyle.js';
import { useCanvas } from '../../../../canvas/hooks/useCanvas.js';
import {
  TRACK_SEPARATOR_COLOR,
  TRACK_SEPARATOR_STROKE_WIDTH,
} from '../../../constants.js';
import { CANVAS_PIXEL_OFFSET } from '../constants.js';

interface AnnotationsLineRendererProps {
  source: Point;
  destination: Point;
  strokeColor: string;
}

export const AnnotationsLineRenderer = (
  props: AnnotationsLineRendererProps,
) => {
  const {
    source,
    destination,
    strokeColor = getTokenComputedStyle(TRACK_SEPARATOR_COLOR),
  } = props;

  const draw = useCallback(
    (ctx: CanvasRenderingContext2D) => {
      ctx.beginPath();
      ctx.moveTo(
        source.x - CANVAS_PIXEL_OFFSET,
        source.y - CANVAS_PIXEL_OFFSET,
      );
      ctx.lineTo(
        destination.x - CANVAS_PIXEL_OFFSET,
        destination.y - CANVAS_PIXEL_OFFSET,
      );
      ctx.lineWidth = TRACK_SEPARATOR_STROKE_WIDTH;
      ctx.strokeStyle = strokeColor;
      ctx.stroke();
      ctx.closePath();

      return false;
    },
    [source, destination, strokeColor],
  );

  useCanvas('annotations-line', draw);

  return null;
};

AnnotationsLineRenderer['displayName'] = 'AnnotationsLineRenderer';
